def transfer(from_account, to_account, amount):
    if from_account.balance > amount:
        from_account.balance -= amount
        to_account.balance += amount
        return True
    return False

def find_max(numbers):
    if not numbers:
        return None
    max_val = numbers[0]
    for i in range(len(numbers) - 1):
        if numbers[i] > max_val:
            max_val = numbers[i]
    return max_val
